"use strict";(self.webpackChunkastrology_garden=self.webpackChunkastrology_garden||[]).push([["1304"],{8645(e,n,i){i.r(n),i.d(n,{metadata:()=>o,default:()=>p,frontMatter:()=>r,contentTitle:()=>t,toc:()=>l,assets:()=>c});var o=JSON.parse('{"id":"Planets & Points/Mars","title":"Mars","description":"Principle:","source":"@site/docs/Planets & Points/Mars.md","sourceDirName":"Planets & Points","slug":"/Planets & Points/Mars","permalink":"/Planets & Points/Mars","draft":false,"unlisted":false,"editUrl":"https://github.com/facebook/docusaurus/tree/main/packages/create-docusaurus/templates/shared/docs/Planets & Points/Mars.md","tags":[],"version":"current","frontMatter":{},"sidebar":"tutorialSidebar","previous":{"title":"Jupiter","permalink":"/Planets & Points/Jupiter"},"next":{"title":"Midheaven","permalink":"/Planets & Points/Midheaven"}}'),a=i(4848),s=i(8453);let r={},t,c={},l=[{value:"T\u0142umaczenie na j\u0119zyk polski (Translation)",id:"t\u0142umaczenie-na-j\u0119zyk-polski-translation",level:3}];function d(e){let n={h3:"h3",li:"li",p:"p",ul:"ul",...(0,s.R)(),...e.components};return(0,a.jsxs)(a.Fragment,{children:[(0,a.jsx)(n.p,{children:"Principle:"}),"\n",(0,a.jsx)(n.p,{children:"Energy."}),"\n",(0,a.jsx)(n.p,{children:"Psychological Correspondence:"}),"\n",(0,a.jsxs)(n.ul,{children:["\n",(0,a.jsxs)(n.li,{children:["\n",(0,a.jsx)(n.p,{children:"Will-power, active energy, courage, determination, enjoyment of work and fighting, the urge to do something."}),"\n"]}),"\n",(0,a.jsxs)(n.li,{children:["\n",(0,a.jsx)(n.p,{children:"Waste of energy, enjoyment of destruction, impulsiveness, ruthlessness, brutality. \u2013 Weakness, lack of energy."}),"\n"]}),"\n"]}),"\n",(0,a.jsx)(n.p,{children:"Biological Correspondence:"}),"\n",(0,a.jsx)(n.p,{children:"The heat of the body, the muscles, the sex functions."}),"\n",(0,a.jsx)(n.p,{children:"Sociological Correspondence:"}),"\n",(0,a.jsx)(n.p,{children:"Fighters, bearers of arms, athletes, mechanics, technicians, craftsmen, surgeons."}),"\n",(0,a.jsx)(n.p,{children:"Position in Houses and Signs:"}),"\n",(0,a.jsx)(n.p,{children:"I. A fighting spirit, the urge to do something, ambition, love of independence. \u2013 Irascibility, destructive urge, impatience, waste of energy. \u2013 Blind zeal is harmful! Danger of injuries to the head, many quarrels."}),"\n",(0,a.jsx)(n.p,{children:"II. Great capacity for work, endurance, practical gifts or abilities, the urge to acquire possessions. \u2013 Obstinacy, intractability, impulsiveness, vindictiveness."}),"\n",(0,a.jsx)(n.p,{children:"III. Mobility, readiness for action, versatile gifts, a ready wit, biting criticism. \u2013 The tendency to scatter one's energies, restlessness, quarrelsomeness."}),"\n",(0,a.jsx)(n.p,{children:"IV. An intense emotional life, subject to moods, impulsiveness, but little perseverance. \u2013 Lack of self-control, moodiness, actions are governed by instinct."}),"\n",(0,a.jsx)(n.p,{children:"V. Formative powers, acting with great self-assurance, great self-confidence, spirit of enterprise, working zeal, the striving for possessions, responsibility. \u2013 The inclination to speculate or to gamble, too much love of self, egoism, unbridled passion."}),"\n",(0,a.jsx)(n.p,{children:"VI. Love of tidiness, endurance in detail-work and in scientific activity, methodical working, exploitation of every situation, adaptation, the urge to criticize, irritability, nervousness."}),"\n",(0,a.jsx)(n.p,{children:"VII. The urge to associate, a friendly and cordial manner assists in attaining success. Enthusiasm, love of team-work. \u2013 Dependence on feeling and mood as well as too much frankness lead to differences."}),"\n",(0,a.jsx)(n.p,{children:"VIII. The survival instinct, the ruthless use of one's energies, ambition, consciousness of goal, a sense of criticism. \u2013 Dissipation of energy, the urge to criticize, the urge to destroy wilfully, the craving for power and authority, selfishness, incompatibility."}),"\n",(0,a.jsx)(n.p,{children:"IX. The need to convince others of one's own ideas. Love of contest and of sport, the display of enthusiasm in one's work, mobility, frankness, candour. \u2013 Rashness, love of adventure, the tendency to be extravagant."}),"\n",(0,a.jsx)(n.p,{children:"X. Ambition, working zeal, endurance, a sense of reality, sober deliberation, the will to attain success, independence. \u2013 Overestimation of self, defiance, obstinacy, egoism."}),"\n",(0,a.jsx)(n.p,{children:"XI. Acting with deliberation, love of freedom, utilisation of new working methods, the urge to reform, team-work, organisation, independence. \u2013 The spirit of contradiction, inconstancy, superficiality."}),"\n",(0,a.jsx)(n.p,{children:"XII. Wait and see attitude in hoping and acting, to work silently, a struggle for recognition, social activity. Interest in the occult (borderline) sciences. The inclination to join secret societies, the craving for alcohol, nicotine, etc. Lack of self-control and unreliability in love-relationship."}),"\n",(0,a.jsx)(n.h3,{id:"t\u0142umaczenie-na-j\u0119zyk-polski-translation",children:"T\u0142umaczenie na j\u0119zyk polski (Translation)"}),"\n",(0,a.jsx)(n.p,{children:"MARS"}),"\n",(0,a.jsx)(n.p,{children:"Zasada:"}),"\n",(0,a.jsx)(n.p,{children:"Energia."}),"\n",(0,a.jsx)(n.p,{children:"Korespondencja psychologiczna:"}),"\n",(0,a.jsxs)(n.ul,{children:["\n",(0,a.jsxs)(n.li,{children:["\n",(0,a.jsx)(n.p,{children:"Si\u0142a woli, aktywna energia, odwaga, determinacja, czerpanie rado\u015Bci z pracy i walki, pragnienie dzia\u0142ania."}),"\n"]}),"\n",(0,a.jsxs)(n.li,{children:["\n",(0,a.jsx)(n.p,{children:"Marnowanie energii, czerpanie rado\u015Bci z niszczenia, impulsywno\u015B\u0107, bezwzgl\u0119dno\u015B\u0107, brutalno\u015B\u0107. \u2013 S\u0142abo\u015B\u0107, brak energii."}),"\n"]}),"\n"]}),"\n",(0,a.jsx)(n.p,{children:"Korespondencja biologiczna:"}),"\n",(0,a.jsx)(n.p,{children:"Ciep\u0142ota cia\u0142a, mi\u0119\u015Bnie, funkcje seksualne."}),"\n",(0,a.jsx)(n.p,{children:"Korespondencja socjologiczna:"}),"\n",(0,a.jsx)(n.p,{children:"Wojownicy, nosz\u0105cy bro\u0144, sportowcy, mechanicy, technicy, rzemie\u015Blnicy, chirurdzy."}),"\n",(0,a.jsx)(n.p,{children:"Pozycja w domach i znakach:"}),"\n",(0,a.jsx)(n.p,{children:"I. Duch walki, pragnienie dzia\u0142ania, ambicja, zami\u0142owanie do niezale\u017Cno\u015Bci. \u2013 Wybuchowo\u015B\u0107, pop\u0119d niszczycielski, niecierpliwo\u015B\u0107, marnowanie energii. \u2013 \u015Alepy krytycyzm (gorliwo\u015B\u0107) jest szkodliwy! Niebezpiecze\u0144stwo uraz\xf3w g\u0142owy, wiele k\u0142\xf3tni."}),"\n",(0,a.jsx)(n.p,{children:"II. Wielka wydajno\u015B\u0107 w pracy, wytrwa\u0142o\u015B\u0107, praktyczne dary lub zdolno\u015Bci, pragnienie zdobywania posiad\u0142o\u015Bci. \u2013 Uparto\u015B\u0107, krn\u0105brno\u015B\u0107, impulsywno\u015B\u0107, m\u015Bciwo\u015B\u0107."}),"\n",(0,a.jsx)(n.p,{children:"III. Mobilno\u015B\u0107, gotowo\u015B\u0107 do dzia\u0142ania, wszechstronne dary, b\u0142yskotliwy dowcip, k\u0105\u015Bliwa krytyka. \u2013 Tendencja do rozpraszania swoich energii, niepok\xf3j, k\u0142\xf3tliwo\u015B\u0107."}),"\n",(0,a.jsx)(n.p,{children:"IV. Intensywne \u017Cycie emocjonalne, uleganie nastrojom, impulsywno\u015B\u0107, lecz niewiele wytrwa\u0142o\u015Bci. \u2013 Brak samokontroli, humorzasto\u015B\u0107, dzia\u0142ania s\u0105 kierowane przez instynkt."}),"\n",(0,a.jsx)(n.p,{children:"V. Si\u0142y tw\xf3rcze (formuj\u0105ce), dzia\u0142anie z du\u017C\u0105 pewno\u015Bci\u0105 siebie, wielka wiara w siebie, duch przedsi\u0119biorczo\u015Bci, gorliwo\u015B\u0107 w pracy, d\u0105\u017Cenie do posiadania, odpowiedzialno\u015B\u0107. \u2013 Sk\u0142onno\u015B\u0107 do spekulacji lub hazardu, zbyt wielka mi\u0142o\u015B\u0107 w\u0142asna, egoizm, nieokie\u0142znana nami\u0119tno\u015B\u0107."}),"\n",(0,a.jsx)(n.p,{children:"VI. Zami\u0142owanie do porz\u0105dku, wytrwa\u0142o\u015B\u0107 w pracy szczeg\xf3\u0142owej i w dzia\u0142alno\u015Bci naukowej, metodyczna praca, wyzyskiwanie ka\u017Cdej sytuacji, adaptacja, pragnienie krytykowania, dra\u017Cliwo\u015B\u0107, nerwowo\u015B\u0107."}),"\n",(0,a.jsx)(n.p,{children:"VII. Potrzeba zrzeszania si\u0119, przyjazny i serdeczny spos\xf3b bycia pomaga w osi\u0105ganiu sukcesu. Entuzjazm, zami\u0142owanie do pracy zespo\u0142owej. \u2013 Zale\u017Cno\u015B\u0107 od uczu\u0107 i nastroju, jak r\xf3wnie\u017C zbyt du\u017Ca szczero\u015B\u0107 prowadz\u0105 do nieporozumie\u0144 (r\xf3\u017Cnic)."}),"\n",(0,a.jsx)(n.p,{children:"VIII. Instynkt przetrwania, bezwzgl\u0119dne korzystanie z w\u0142asnych energii, ambicja, \u015Bwiadomo\u015B\u0107 celu, zmys\u0142 krytycyzmu. \u2013 Rozproszenie energii, pragnienie krytykowania, pragnienie umy\u015Blnego niszczenia, \u0142aknienie w\u0142adzy i autorytetu, samolubstwo, niezgodno\u015B\u0107."}),"\n",(0,a.jsx)(n.p,{children:"IX. Potrzeba przekonywania innych do w\u0142asnych pomys\u0142\xf3w. Zami\u0142owanie do rywalizacji i sportu, okazywanie entuzjazmu w swojej pracy, mobilno\u015B\u0107, szczero\u015B\u0107, otwarto\u015B\u0107. \u2013 Lekkomy\u015Blno\u015B\u0107, zami\u0142owanie do przyg\xf3d, tendencja do bycia ekstrawaganckim."}),"\n",(0,a.jsx)(n.p,{children:"X. Ambicja, gorliwo\u015B\u0107 w pracy, wytrwa\u0142o\u015B\u0107, poczucie rzeczywisto\u015Bci, trze\u017Awa rozwaga, wola osi\u0105gni\u0119cia sukcesu, niezale\u017Cno\u015B\u0107. \u2013 Przecenianie samego siebie, przekora, uparto\u015B\u0107, egoizm."}),"\n",(0,a.jsx)(n.p,{children:"XI. Dzia\u0142anie z rozwag\u0105, zami\u0142owanie do wolno\u015Bci, wykorzystywanie nowych metod pracy, pragnienie reformowania, praca zespo\u0142owa, organizacja, niezale\u017Cno\u015B\u0107. \u2013 Duch przekory (sprzeczno\u015Bci), niesta\u0142o\u015B\u0107, powierzchowno\u015B\u0107."}),"\n",(0,a.jsx)(n.p,{children:"XII. Postawa wyczekuj\u0105ca w nadziei i dzia\u0142aniu, cicha praca, walka o uznanie, aktywno\u015B\u0107 spo\u0142eczna. Zainteresowanie naukami okultystycznymi (pogranicznymi). Sk\u0142onno\u015B\u0107 do wst\u0119powania do tajnych stowarzysze\u0144, \u0142aknienie alkoholu, nikotyny itp. Brak samokontroli i nielojalno\u015B\u0107 (zawodno\u015B\u0107) w relacjach mi\u0142osnych."})]})}function p(e={}){let{wrapper:n}={...(0,s.R)(),...e.components};return n?(0,a.jsx)(n,{...e,children:(0,a.jsx)(d,{...e})}):d(e)}},8453(e,n,i){i.d(n,{R:()=>r,x:()=>t});var o=i(6540);let a={},s=o.createContext(a);function r(e){let n=o.useContext(s);return o.useMemo(function(){return"function"==typeof e?e(n):{...n,...e}},[n,e])}function t(e){let n;return n=e.disableParentContext?"function"==typeof e.components?e.components(a):e.components||a:r(e.components),o.createElement(s.Provider,{value:n},e.children)}}}]);